import React, { useCallback, useState } from 'react';
import './App.css';
import Header from './components/header/header';
import navigationValues from './navList';

// Create a navigation context with a default of home
const navigationContext = React.createContext(navigationValues.home);

function App() {
  // This is the wrapper - callback is allowing us to expose this to a children. The [] is saying it has no dependencies.
  const navigate = useCallback((navTo : any) => setNav({current: navTo, navigate}), []);

  // Use state for the navigation. We are setting the default to be "home" but then passing in a value for the callback for when it changes.
  const [nav, setNav] = useState({current: navigationValues.home, navigate});
  return (
    <navigationContext.Provider value={nav}>
      <Header/>      
    </navigationContext.Provider>    
  );
}

// Export the context as we want it to be available in child components.
export {navigationContext};
export default App;
